const fs = require('fs');
const path = require('path');

const LESSONS_DIR = path.join(__dirname, '..', 'lessons');
const INDEX_PATH = path.join(LESSONS_DIR, 'index.json');

// Load existing index
const index = JSON.parse(fs.readFileSync(INDEX_PATH, 'utf8'));
const startIdx = index.length; // 38

// Helper to create a lesson
function L(title, sub, xp, content, q, o, c, exp) {
  return { title, sub, xp, content, quiz: { q, o, c, exp } };
}

